def next_permutation(xs):
    n = len(xs)
    if n <= 1:
        return
    i = n - 2
    while i >= 0 and xs[i] >= xs[i + 1]:
        i -= 1
    if i >= 0:
        j = n - 1
        while xs[j] <= xs[i]:
            j -= 1
        xs[i], xs[j] = xs[j], xs[i]
    left, right = i + 1, n - 1
    while left < right:
        xs[left], xs[right] = xs[right], xs[left]
        left += 1
        right -= 1
